#include<bits/stdc++.h>
using namespace std;
long long n,h[200010];
vector<long long> mp[200010];
struct node
{
    long long a,b,c;
};
vector<node> ans;
void dfs1(long long x,long long fa=-1)
{
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            dfs1(i,x);
            if(h[i]>0)
            {
                ans.push_back((node){i,x,h[i]});
            }
            h[x]+=h[i];
        }
    }
}
void dfs2(long long x,long long fa=-1)
{
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            if(h[i]<0)
            {
                ans.push_back((node){x,i,-h[i]});
            }
            dfs2(i,x);
        }
    }
}
int main()
{
    scanf("%lld",&n);
    long long sum=0;
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&h[i]);
        sum+=h[i];
    }
    for(long long i=1;i<n;i++)
    {
        long long u,v;
        scanf("%lld%lld",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    sum/=n;
    for(long long i=1;i<=n;i++)
    {
        h[i]-=sum;
    }
    dfs1(1);
    dfs2(1);
    printf("%lld\n",ans.size());
    for(node i:ans)
    {
        printf("%lld %lld %lld\n",i.a,i.b,i.c);
    }
    return 0;
}
